mapper.select:
select g.group_id, g.group_name, g.create_by, g.create_time, g.remark
from cnsl_template_group g, cnsl_template_group_version gv
where g.group_id = gv.group_id and gv.version_id = #{versionId}

mapper.update:
update cnsl_template_group
group_name = #{groupName}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, remark = #{remark},
where group_id = #{groupId}
